  84→export async function autoSelectSticker(reply: string): Promise<string | null> {
  85→  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
  86→  if (!emotionVectors) {
  87→    emotionVectors = new Map();
  88→    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
  89→      const vec = await embedText(repr);
  90→      if (vec) emotionVectors.set(emotion, vec);
  91→    }
  92→  }
  93→  const queryVec = await embedText(reply);
  94→  if (!queryVec) return null;
  95→  let best = "";
  96→  let bestScore = 0;
  97→  for (const [emotion, vec] of emotionVectors) {
  98→    const score = cosineSim(queryVec, vec);
  99→    if (score > bestScore) { bestScore = score; best = emotion; }
 100→  }
 101→  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
 102→}
