 166→// ─── Orphan turn flusher ──────────────────────────────────────────────────────
 167→//
 168→// Delivers agent output that arrived with NO active prompt turn — e.g. a
 169→// Claude Code harness background sub-agent completes and re-invokes the agent
 170→// via task-notification, producing an agent_message_chunk while runPrompt's
 171→// request→response flush path isn't listening (see SPEC-orphan-turn-flusher).
 172→//
 173→// SessionManager buffers + debounces those chunks and calls this on quiescence
 174→// (wired via sessions.onOrphanTurn in index.ts). This reuses the SAME reply
 175→// transform (transformReplyTokens) + render/split helpers as the normal turn —
 176→// there is deliberately NO second transform. Tokens that only make sense inside
 177→// a live turn (GOAL_DONE / RESTART / CONTINUE / WIKI_QUERY / SKILL_PROPOSE /
 178→// SPECIALIST_PROXY / relay*) are intentionally ignored here; user-facing tokens
 179→// (text / SEND_FILE / ASK / SCHEDULE / STICKER) are delivered.
 180→export async function flushOrphanTurn(session: ChatSession, rawText: string): Promise<void> {
 181→  const { bot, rateLimitedUntil, queuePendingMessage, scheduler, scheduleStore } = deps();
 182→  const chatId = session.chatId;
 183→
 184→  // Dedup: skip content already delivered (e.g. same summary that also came
 185→  // through a normal turn, or a duplicate orphan flush). Shares the 5-min
 186→  // window used by specialist/parallel result injection.
 187→  if (isDuplicateResult(chatId, rawText)) {
 188→    console.log(`[orphan ${chatId}] skipped (dedup hit)`);
 189→    return;
 190→  }
 191→
 192→  const ab7 = transformReplyTokens(rawText, {
 193→    parseDuration,
 194→    parseAbsoluteTime,
 195→    parseRecurrence,
 196→    computeNextRunAt,
 197→  });
 198→
 199→  // SCHEDULE tokens — register the same way the normal path does.
 200→  const scheduleReceipts: string[] = [];
 201→  for (const se of ab7.scheduleTokens) {
 202→    try {
 203→      const entry = await scheduleStore.add({
 204→        chatId,
 205→        userId: session.userId ?? chatId,
 206→        runAt: se.runAt,
 207→        prompt: se.prompt,
 208→        recurrence: se.recurrence,
 209→      });
 210→      scheduler.arm(entry);
 211→      const delta = formatRelative(se.runAt - Date.now());
 212→      const recurTag = se.recurrence ? ` [${formatRecurrence(se.recurrence)}]` : "";
 213→      scheduleReceipts.push(
 214→        `⏰ 已排程 ${entry.id}${recurTag}，${delta} 後觸發（${new Date(se.runAt).toLocaleString()}）`,
 215→      );
 216→    } catch (err) {
 217→      console.error(`[orphan ${chatId}] schedule token register failed:`, err);
 218→    }
 219→  }
 220→
 221→  // Surface (but don't act on) tokens that require live-turn context.
 222→  const ignored: string[] = [];
 223→  if (ab7.goalDone) ignored.push("GOAL_DONE");
 224→  if (ab7.restartToken) ignored.push("RESTART");
 225→  if (ab7.continueToken) ignored.push("CONTINUE");
 226→  if (ab7.wikiQuery) ignored.push("WIKI_QUERY");
 227→  if (ab7.skillPropose) ignored.push("SKILL_PROPOSE");
 228→  if (ab7.specialistProxy) ignored.push("SPECIALIST_PROXY");
 229→  if (ab7.moaPlan) ignored.push("MOA_PLAN");
 230→  if (ignored.length) {
 231→    console.log(`[orphan ${chatId}] ignoring turn-context token(s): ${ignored.join(", ")}`);
 232→  }
 233→
 234→  const body = scheduleReceipts.length
 235→    ? (ab7.text ? `${ab7.text}\n\n${scheduleReceipts.join("\n")}` : scheduleReceipts.join("\n"))
 236→    : ab7.text;
 237→  const askKeyboard = buildAskKeyboard(ab7.askTokens);
 238→
 239→  // Text delivery (chunked). Rate-limit aware: queue for replay if throttled.
 240→  if (body.trim().length > 0) {
 241→    const chunks = splitForTelegram(body);
 242→    for (let i = 0; i < chunks.length; i++) {
 243→      const isLast = i === chunks.length - 1;
 244→      const pageTag = chunks.length > 1 ? `(${i + 1}/${chunks.length})\n` : "";
 245→      const text = pageTag + chunks[i];
 246→      const extra = isLast && askKeyboard ? { reply_markup: askKeyboard } : undefined;
 247→      if (rateLimitedUntil() > Date.now()) {
 248→        queuePendingMessage(chatId, text);
 249→        continue;
 250→      }
 251→      try {
 252→        const msg = await bot.api.sendMessage(chatId, text, extra);
 253→        if (isLast && askKeyboard && msg?.message_id !== undefined) {
 254→          askRegistry.set(msg.message_id, ab7.askTokens);
 255→        }
 256→      } catch (err) {
 257→        console.error(`[orphan ${chatId}] chunk send failed, queueing for replay:`, err);
 258→        queuePendingMessage(chatId, text);
 259→      }
 260→      if (!isLast) await new Promise<void>((r) => setTimeout(r, 1100));
 261→    }
 262→  } else if (askKeyboard) {
 263→    // ASK-only orphan turn (rare) — carry the keyboard on a minimal message.
 264→    try {
 265→      const msg = await bot.api.sendMessage(chatId, "（背景任務完成）", { reply_markup: askKeyboard });
 266→      if (msg?.message_id !== undefined) askRegistry.set(msg.message_id, ab7.askTokens);
 267→    } catch (err) {
 268→      console.error(`[orphan ${chatId}] ask-only send failed:`, err);
 269→    }
 270→  }
 271→
 272→  // SEND_FILE — sendFilesByPaths needs a Context-like; build a minimal shim.
 273→  if (ab7.sendFiles.length > 0) {
 274→    const fakeCtx = {
 275→      chat: { id: chatId, type: "private" as const },
 276→      replyWithPhoto: (f: unknown, extra?: unknown) => bot.api.sendPhoto(chatId, f as any, extra as any),
 277→      replyWithDocument: (f: unknown, extra?: unknown) => bot.api.sendDocument(chatId, f as any, extra as any),
 278→    } as unknown as Context;
 279→    try {
 280→      await sendFilesByPaths(fakeCtx, ab7.sendFiles);
 281→    } catch (err) {
 282→      console.error(`[orphan ${chatId}] sendFilesByPaths failed:`, err);
 283→    }
 284→  }
 285→
 286→  // Stickers
 287→  for (const emotion of ab7.stickerEmotions) {
 288→    const fileId = STICKER_MAP[emotion];
 289→    if (!fileId) continue;
 290→    try {
 291→      await bot.api.sendSticker(chatId, fileId);
 292→    } catch (err) {
 293→      console.warn(`[orphan ${chatId}] sticker ${emotion} failed — ${(err as Error).message}`);
 294→    }
 295→  }
 296→
 297→  console.log(
 298→    `[orphan ${chatId}] delivered (textChars=${body.length}, files=${ab7.sendFiles.length}, ` +
 299→      `asks=${ab7.askTokens.length}, schedules=${scheduleReceipts.length}, stickers=${ab7.stickerEmotions.length})`,
 300→  );
 301→}
