 303→// ─── runPrompt ────────────────────────────────────────────────────────────────
 304→
 305→export async function runPrompt(
 306→  ctx: Context,
 307→  session: ChatSession,
 308→  text: string,
 309→  mode: RunPromptMode = { kind: "user" },
 310→) {
 311→  const { bot, sessions, rateLimitedUntil, onRateLimitRecovery, queuePendingMessage,
 312→    handleRestart, STREAM_EDIT_INTERVAL_MS, MEMORY_DIR, scheduler, scheduleStore } = deps();
 313→
 314→  const continuationContext: ContinuationContext | undefined =
 315→    mode.kind === "continuation" ? mode.context : undefined;
 316→  const isMeta = mode.kind === "meta";
 317→  const isSilentMeta = mode.kind === "meta" && mode.silent === true;
 318→  const relayReplyTo = mode.kind === "relay" ? mode.replyTo : undefined;
 319→  const isRelay = mode.kind === "relay";
 320→  // Optional header prepended to the visible reply (and shown in the "Thinking…"
 321→  // placeholder). Used e.g. by ASK button clicks to record "我選擇了：X" in the
 322→  // reply itself, so the original button message isn't rewritten and no extra
 323→  // message is sent. Render-only — NOT added to agent history/memory.
 324→  const replyHeader = mode.kind === "user" ? mode.replyHeader : undefined;
 325→  const chatId = ctx.chat!.id;
 326→
 327→  // Guard against concurrent prompts on the same ACP session.
 328→  if (session.inflight) {
 329→    if (relayReplyTo) {
 330→      sendRelay(relayReplyTo, "小X 目前上一輪還在處理中，稍後再回覆。").catch((err) =>
 331→        console.error(`[chat ${chatId}] relay busy notice to ${relayReplyTo} failed:`, err),
 332→      );
 333→      notifyRelayOwner(
 334→        bot,
 335→        config.allowedUserIds[0] ?? 0,
 336→        `⏳ 「${relayReplyTo}」又送來 relay 訊息，但上一輪還在處理中，已擋掉這次重複注入。`,
 337→        `busy notice for ${relayReplyTo}`,
 338→      );
 339→      return;
 340→    }
 341→    if (isMeta) {
 342→      console.log(`[chat ${chatId}] meta prompt queued (session inflight)`);
 343→      session._pendingMetaQueue.push({ ctx: ctx as unknown as any, prompt: text, opts: mode as any });
 344→      return;
 345→    }
 346→    await ctx.reply(
 347→      "⏳ 上一個回合還在進行中。請等它結束，或先用 /cancel 取消。",
 348→    );
 349→    return;
 350→  }
 351→  session.inflight = true;
 352→  sessions.resetTurn(session);
 353→  petState("thinking");
 354→
 355→  let continuationPlan: ContinuationPlan | null = null;
 356→  let continueTokenFired = false;
 357→  let pendingRestartReason: string | null = null;
 358→
 359→  if (!continuationContext) {
 360→    session.history.push({ role: "user", text, timestamp: Date.now() });
 361→    // 多 session auto-naming：首則 user 訊息當預設名。fire-and-forget——
 362→    // 寫 store 在 prompt hot path，絕不 await 阻塞；只填空名（冪等，
 363→    // resume 後 history 歸零重複觸發無害）。
 364→    if (config.acpSessionResume && session.activeProvider === "acp" &&
 365→        session.history.filter((h) => h.role === "user").length === 1) {
 366→      import("./session-registry.js")
 367→        .then((m) => m.autoNameActive(session.chatId, text))
 368→        .catch(() => {});
 369→    }
 370→  }
 371→  session.charsIn += text.length;
 372→
 373→  // Context Budget Warning: inject once when context reaches 70%
 374→  let budgetWarning = "";
 375→  if (!session._budgetWarned && config.contextWindowTokens) {
 376→    const totalChars = session.preambleBreakdown.total + session.charsIn + session.charsOut;
 377→    const estimatedTokens = Math.ceil(totalChars / 4);
 378→    if (estimatedTokens > config.contextWindowTokens * 0.7) {
 379→      session._budgetWarned = true;
 380→      budgetWarning =
 381→        "\n\n[⚠️ Context Budget Warning: session context has reached ~70% capacity. " +
 382→        "Consider wrapping up the current task, using remember() to save important state, " +
 383→        "and preparing for a <<RESTART:context budget>> if needed. " +
 384→        "Avoid starting new multi-step tasks.]\n\n";
 385→      console.log(`[budget] chat ${chatId} hit 70% context (${estimatedTokens}/${config.contextWindowTokens} tok)`);
 386→    }
 387→  }
 388→
 389→  let promptText = text;
 390→  if (!session.preambleInjected && session.memoryPreamble) {
 391→    promptText = session.memoryPreamble + text;
 392→    session.preambleInjected = true;
 393→  }
 394→  if (budgetWarning) {
 395→    promptText = budgetWarning + promptText;
 396→  }
 397→
 398→  const replyToId = ctx.message?.message_id;
 399→  const placeholderText = continuationContext
 400→    ? `↻ Continuing (${continuationContext.turnIndex}/${continuationContext.maxTurns}) toward goal…`
 401→    : replyHeader
 402→      ? `${replyHeader}\n\nThinking…`
 403→      : "Thinking…";
 404→  let placeholder: { message_id: number } | undefined;
 405→  if (!isRelay && !isSilentMeta) {
 406→    try {
 407→      placeholder = await ctx.reply(placeholderText, {
 408→        ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
 409→      });
 410→    } catch (err: any) {
 411→      const desc = err?.description || err?.error?.description || "";
 412→      if (replyToId && /message to be replied not found/i.test(desc)) {
 413→        placeholder = await ctx.reply(placeholderText);
 414→      } else {
 415→        throw err;
 416→      }
 417→    }
 418→  }
 419→
 420→  // Store placeholder msgId for optimistic cancel UI feedback
 421→  session._placeholderMsgId = placeholder?.message_id;
 422→
 423→  let lastEditAt = 0;
 424→  let lastRendered = "";
 425→  let editTimer: NodeJS.Timeout | null = null;
 426→  let throttledSnapshotLogged = false;
 427→  let turnHitRateLimit = false;
 428→  let turnFinalized = false;
 429→
 430→  const editNow = async () => {
 431→    if (!placeholder) return;
 432→    if (rateLimitedUntil() > Date.now()) {
 433→      turnHitRateLimit = true;
 434→      if (!throttledSnapshotLogged) {
 435→        throttledSnapshotLogged = true;
 436→        const snapshot = (session.buffer || "").trim();
 437→        const preview = snapshot.length > 800
 438→          ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
 439→          : snapshot;
 440→        console.warn(
 441→          `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
 442→        );
 443→      }
 444→      return;
 445→    }
 446→    const { content, parseMode } = renderReply(session, false, scheduleParsers);
 447→    if (content === lastRendered) return;
 448→    lastRendered = content;
 449→    lastEditAt = Date.now();
 450→    try {
 451→      if (config.tgRichStreamEnabled) {
 452→        const richEdited = await tryEditRichMessageDraft(ctx.api, chatId, placeholder.message_id, content);
 453→        if (richEdited) return;
 454→      }
 455→      await ctx.api.editMessageText(chatId, placeholder.message_id, content,
 456→        parseMode ? { parse_mode: parseMode } : {});
 457→    } catch {
 458→      // Telegram returns 400 if content identical; ignore.
 459→    }
 460→  };
 461→
 462→  const unregisterRecovery = isRelay || isSilentMeta ? () => {} : onRateLimitRecovery(() => {
 463→    if (turnFinalized) {
 464→      console.log(
 465→        `[rate-limit] chat ${chatId} recovery callback suppressed — turn already finalized`
 466→      );
 467→      return;
 468→    }
 469→    throttledSnapshotLogged = false;
 470→    console.log(
 471→      `[rate-limit] chat ${chatId} resuming edits — pushing latest buffer (${(session.buffer || "").length} chars)`
 472→    );
 473→    lastRendered = "";
 474→    return editNow();
 475→  });
 476→
 477→  session.onUpdate = isRelay
 478→    ? undefined
 479→    : () => {
 480→        const elapsed = Date.now() - lastEditAt;
 481→        if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
 482→          editNow();
 483→        } else if (!editTimer) {
 484→          editTimer = setTimeout(() => {
 485→            editTimer = null;
 486→            editNow();
 487→          }, STREAM_EDIT_INTERVAL_MS - elapsed);
 488→        }
 489→      };
 490→
 491→
 492→  try {
 493→    // Self-fusion: for goal high-stakes decisions, get alternative perspective
 494→    if (mode.kind === "user" && !isMeta) {
 495→      const gs = await goalStore.get(config.memoryDir, chatId).catch(() => null);
 496→      if (gs?.status === "active" && text.length > 50) {
 497→        const decisionSignals = /\b(選|choose|pick|decide|recommend|architecture|刪除|delete|migrate|重構|refactor|方案|approach)\b/i;
 498→        if (decisionSignals.test(text)) {
 499→          const { trioInfer } = await import("./trio-llm.js");
 500→          const altResp = await trioInfer(text.slice(0, 500), {
 501→            system: "You are a contrarian advisor. Give a brief alternative perspective or risk consideration for this decision. 2-3 sentences max.",
 502→            maxTokens: 150, temperature: 0.9, timeout: 8_000,
 503→          });
 504→          if (altResp.text && altResp.source !== "none") {
 505→            const fusion = await synthesizeDualPath(text.slice(0, 200), "（主模型即將回覆）", altResp.text);
 506→            if (fusion) {
 507→              promptText = buildFusionContext(text.slice(0, 200), fusion) + "\n" + promptText;
 508→            } else {
 509→              promptText = `[Alternative perspective (${altResp.source})]\n${altResp.text}\n[End]\n\n` + promptText;
 510→            }
 511→          }
 512→        }
 513→      }
 514→    }
 515→
 516→    const { stopReason } = await session.client.prompt(promptText);
 517→    if (editTimer) {
 518→      clearTimeout(editTimer);
 519→      editTimer = null;
 520→    }
 521→    turnFinalized = true;
 522→    session._placeholderMsgId = undefined;
 523→
 524→    if (session.buffer) {
 525→      session.history.push({ role: "assistant", text: session.buffer, timestamp: Date.now() });
 526→    }
 527→
 528→    const toolLines = toolPrefixLines(session);
 529→    const toolsPrefix = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
 530→
 531→    // Extract relay tokens before ab7 (it doesn't know them).
 532→    const relayTokens: { target: string; text: string }[] = [];
 533→    const relayFileTokens: { target: string; path: string }[] = [];
 534→    const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];
 535→    const relayResultTokens: { target: string; payload: ResultPayload }[] = [];
 536→    const parallelDelegateTasks: ParallelTask[] = [];
 537→    const RELAY_RE = /<<RELAY:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
 538→    const RELAY_FILE_RE = /<<RELAY_FILE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
 539→    const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
 540→    const RELAY_RESULT_RE = /<<RELAY_RESULT:\s*([^|>\r\n]+?)\s*\|\s*(\{[^>\r\n]+?\})\s*>>/g;
 541→    const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
 542→    {
 543→      const { masked, restore } = maskCodeRegions(session.buffer);
 544→      const stripped = masked
 545→        .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {
 546→          let p: DelegatePayload;
 547→          try {
 548→            p = JSON.parse(body) as DelegatePayload;
 549→            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
 550→          } catch {
 551→            p = { id: `rd_${Date.now()}`, goal: body.trim() };
 552→          }
 553→          if (p.goal && !isRelayDelegatePlaceholderGoal(p.goal)) {
 554→            relayDelegateTokens.push({ target: target.trim(), payload: p });
 555→          }
 556→          return "";
 557→        })
 558→        .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {
 559→          try {
 560→            const p = JSON.parse(json) as ResultPayload;
 561→            relayResultTokens.push({ target: target.trim(), payload: p });
 562→          } catch { /* malformed JSON — ignore */ }
 563→          return "";
 564→        })
 565→        .replace(RELAY_RE, (_m, target: string, msg: string) => {
 566→          relayTokens.push({ target: target.trim(), text: msg.trim() });
 567→          return "";
 568→        })
 569→        .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {
 570→          relayFileTokens.push({ target: target.trim(), path: p.trim() });
 571→          return "";
 572→        })
 573→        .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {
 574→          parallelDelegateTasks.push({
 575→            taskId: taskId.trim(),
 576→            target: target.trim(),
 577→            payload: { id: taskId.trim(), goal: prompt.trim() },
 578→          });
 579→          return "";
 580→        });
 581→      session.buffer = restore(stripped);
 582→    }
 583→
 584→    // Fallback: recover RELAY_DELEGATE from streaming captures
 585→    if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {
 586→      const RELAY_DELEGATE_RE2 = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
 587→      for (const raw of session._streamingDelegates) {
 588→        RELAY_DELEGATE_RE2.lastIndex = 0;
 589→        const m = RELAY_DELEGATE_RE2.exec(raw);
 590→        if (m) {
 591→          let p: DelegatePayload;
 592→          try {
 593→            p = JSON.parse(m[2]) as DelegatePayload;
