1442→            const display = stripMemoryTokens(output).trim();
1443→            const proxyStats2 = getProxyStats(chatId);
1444→            const proxyUsage2 = (() => {
1445→              if (!proxyStats2) return "";
1446→              const inTok = Math.ceil(proxyStats2.charsIn / 4);
1447→              const outTok = Math.ceil(proxyStats2.charsOut / 4);
1448→              const totalTok2 = inTok + outTok;
1449→              const limit = config.contextWindowTokens;
1450→              const pctStr = limit ? ((totalTok2 / limit) * 100).toFixed(1) + "%" : "";
1451→              return `\n\n— ctx ~${totalTok2}/${limit} tok (${pctStr}) • in ${inTok} · out ${outTok}`;
1452→            })();
1453→            if (display) {
1454→              const final = `${prefix}${display.length > TG_MAX ? "…" + display.slice(-TG_MAX) : display}${proxyUsage2}`;
1455→              await bot.api.editMessageText(chatId, proxyPlaceholder.message_id, final, { parse_mode: "Markdown" })
1456→                .catch(() => bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `🤖 [${name}]\n${display}${proxyUsage2}`).catch(() => {}));
1457→            } else {
1458→              await bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `${prefix}(no response)`, { parse_mode: "Markdown" }).catch(() => {});
1459→            }
1460→            if (proxyDone) {
1461→              const proxySession = endProxy(chatId);
1462→              await bot.api.sendMessage(chatId, `✅ Specialist "${name}" 完成，已切回主 agent。`).catch(() => {});
1463→              if (proxySession) {
1464→                const summary2 = buildProxySummary(proxySession);
1465→                const userId = ctx.from?.id ?? chatId;
1466→                const s2 = await sessions.get(chatId, userId);
1467→                runPrompt(ctx, s2, summary2, { kind: "meta" }).catch(() => {});
1468→              }
1469→            }
1470→          } catch (err) {
1471→            if (proxyEditTimer) { clearTimeout(proxyEditTimer); proxyEditTimer = null; }
1472→            console.error(`[chat ${chatId}] specialist proxy initial prompt failed:`, err);
1473→            bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `⚠️ Specialist "${name}" 初始回覆失敗：${(err as Error).message}`).catch(() => {});
1474→            endProxy(chatId);
1475→          }
1476→        });
1477→    }
1478→
1479→    // Hoist <<CONTINUE>> flag
1480→    if (!isMeta && ab7.continueToken) continueTokenFired = true;
1481→    petState("done");
1482→    const petSummary = (session.buffer || "").replace(/<<[^>]+>>/g, "").trim().slice(0, 80);
1483→    if (petSummary) petEmit({ type: "reply", text: petSummary });
1484→
1485→
1486→  } catch (err) {
1487→    const e = err as Error & { code?: number; data?: unknown };
1488→    petState("error", e.message?.slice(0, 60));
1489→    console.error(
1490→      `[chat ${chatId}] prompt failed:`,
1491→      e.code !== undefined ? `code=${e.code}` : "",
1492→      e.message,
1493→      e.data !== undefined ? `data=${JSON.stringify(e.data)}` : "",
1494→      session.stderrTail ? `\nstderr:\n${session.stderrTail}` : ""
1495→    );
1496→    let msg = `Error: ${e.message}`;
1497→    if (e.code === -32603) {
1498→      const tail = session.stderrTail.trim();
1499→      if (/prompt already in progress/i.test(e.message)) {
1500→        msg =
1501→          "⏳ 上一個回合還在進行中，kiro-cli 拒絕了這次的請求。\n" +
1502→          "請等它結束，或先用 /cancel 取消再重試。";
1503→      } else if (tail) {
1504→        const snippet = tail.length > 500 ? "…" + tail.slice(-500) : tail;
1505→        msg += `\n\nAgent stderr:\n${snippet}`;
1506→      } else {
1507→        msg +=
1508→          "\n\nThis is a JSON-RPC internal error from the ACP agent. " +
1509→          "Common causes: kiro-cli not logged in, credentials expired, " +
1510→          "or the model call failed. Try running `kiro-cli` manually to " +
1511→          "confirm it works, or re-run the bridge with DEBUG_ACP=1 for " +
1512→          "full agent logs.";
1513→      }
1514→    }
1515→    // 額度用盡 / 限流錯誤 → 附上 /model 切換提示（ACP 的額度訊息常在 stderr）
1516→    const hint = quotaHint(`${e.message ?? ""}\n${session.stderrTail ?? ""}`);
1517→    if (hint) msg += `\n\n${hint}`;
1518→    if (relayReplyTo) {
1519→      sendRelay(relayReplyTo, msg).catch((err2) =>
1520→        console.error(`[chat ${chatId}] relay error notice to ${relayReplyTo} failed:`, err2));
1521→      return;
1522→    }
1523→    try {
1524→      if (!placeholder) throw new Error("missing placeholder");
1525→      await ctx.api.editMessageText(chatId, placeholder.message_id, msg);
1526→    } catch {
1527→      await ctx.reply(msg);
1528→    }
1529→  } finally {
1530→    if (editTimer) {
1531→      clearTimeout(editTimer);
1532→      editTimer = null;
1533→    }
1534→    unregisterRecovery();
1535→    session.onUpdate = undefined;
1536→    session.inflight = false;
1537→    sessions.clearInactivityTimer(session);
1538→    if (session._pendingMetaQueue.length > 0) {
1539→      const queued = session._pendingMetaQueue.splice(0);
1540→      console.log(`[chat ${chatId}] draining ${queued.length} pending meta prompt(s)`);
1541→      setTimeout(async () => {
1542→        for (const item of queued) {
1543→          try {
1544→            await runPrompt(item.ctx as Context, session, item.prompt, item.opts as any);
1545→          } catch (err) {
1546→            console.error(`[chat ${chatId}] pending meta drain failed:`, err);
1547→          }
1548→        }
1549→      }, 500);
1550→    }
1551→  }
1552→
1553→  // Post-finally: RESTART takes priority
1554→  if (pendingRestartReason !== null) {
1555→    if (continuationPlan !== null) {
1556→      console.warn(`[chat ${chatId}] RESTART + continuationPlan both present; clearing continuationPlan`);
1557→      continuationPlan = null;
1558→    }
1559→    console.log(`[chat ${chatId}] RESTART accepted; triggering shutdown (reason="${pendingRestartReason}")`);
1560→    handleRestart(ctx, { reason: pendingRestartReason }).catch((err) => {
1561→      console.error(`[chat ${chatId}] handleRestart failed:`, err);
1562→    });
1563→    return;
1564→  }
1565→
1566→  // AB-7b: schedule next continuation turn
1567→  if (continuationPlan) {
1568→    const planSnapshot = continuationPlan;
1569→    cancelPendingContinuation(chatId);
1570→    const timer = setTimeout(() => {
1571→      pendingContinuations.delete(chatId);
1572→      const continuationPrompt =
1573→        `[bridge continuation — do not reply to this literally, just continue working toward the goal]\n\n` +
1574→        `Continue toward your standing goal (turn ${planSnapshot.turnIndex}/${planSnapshot.maxTurns}).\n` +
1575→        `Objective: ${planSnapshot.objective}` +
1576→        (planSnapshot.lastReason
1577→          ? `\nPrevious turn preview: ${planSnapshot.lastReason}`
1578→          : "");
1579→      runPrompt(ctx, session, continuationPrompt, {
1580→        kind: "continuation",
1581→        context: planSnapshot,
1582→      }).catch((err) => {
1583→        console.error(`[chat ${chatId}] continuation runPrompt failed:`, err);
1584→      });
1585→    }, GOAL_CONTINUATION_DELAY_MS);
1586→    pendingContinuations.set(chatId, timer);
1587→  }
1588→
1589→  // <<CONTINUE>> token
1590→  if (!continuationPlan && !pendingRestartReason && continueTokenFired) {
1591→    cancelPendingContinuation(chatId);
1592→    const timer = setTimeout(() => {
1593→      pendingContinuations.delete(chatId);
1594→      runPrompt(ctx, session, "[bridge continuation — continue where you left off]", {
1595→        kind: "continuation",
1596→        context: { turnIndex: 1, maxTurns: 1, objective: "continue", lastReason: null },
1597→      }).catch((err) => {
1598→        console.error(`[chat ${chatId}] CONTINUE runPrompt failed:`, err);
1599→      });
1600→    }, GOAL_CONTINUATION_DELAY_MS);
1601→    pendingContinuations.set(chatId, timer);
1602→    console.log(`[chat ${chatId}] <<CONTINUE>> token: scheduling follow-up turn`);
1603→  }
1604→}
