  1→// Unified bridge-token extraction. Replaces the three separate
  2→// extract*Tokens functions that index.ts defined inline. Covers:
  3→//
  4→//   <<SEND_FILE:abs-path>>      — existing
  5→//   <<SCHEDULE:time|prompt>>    — existing
  6→//   <<ASK:question_id|...>>     — existing
  7→//   <<SKILL_USED:name|reason>>  — new (AB-1)
  8→//   <<GOAL_DONE:reason>>        — new (AB-1)
  9→//
 10→// Token syntax, limits, and semantics are defined by
 11→// `docs/ab-token-protocol.md`. This module is the one extraction path —
 12→// no parallel implementations anywhere.
 13→//
 14→// Design notes:
 15→//
 16→//  • Code-region masking is mandatory for every regex. Agents frequently
 17→//    paste token examples inside ``` fenced or `inline` code blocks to
 18→//    explain the protocol; without masking those examples would be
 19→//    treated as live tokens and accidentally trigger real side effects.
 20→//    The mask/restore pair lives here and is private — callers don't
 21→//    need to know about sentinels.
 22→//
 23→//  • ASK parsing keeps its full-featured parseAskInner function inline
 24→//    here so SKILL_USED's simpler parser can sit next to it. The
 25→//    Telegram-UI layer (buildAskKeyboard / askRegistry / replyWithAsk)
 26→//    stays in index.ts — that's not transformation, it's rendering.
 27→//
 28→//  • SCHEDULE's time-parsing dependencies (parseDuration,
 29→//    parseAbsoluteTime, parseRecurrence, computeNextRunAt) are injected
 30→//    via the `scheduleParsers` parameter of `transform()` so this file
 31→//    doesn't pull in the whole schedule-store module graph.
 32→
 33→import type { Recurrence } from "./recurrence.js";
 34→import { STICKER_MAP } from "./stickerMap.js";
 35→
 36→// ───────────────────────────────────────────────────────────────────────
 37→// Regexes — one per token. Each is anchored with `<<NAME:` prefix and
 38→// terminates at `>>`. Payload body rejects `>` and CRLF so a stray `>`
 39→// inside the payload terminates cleanly instead of eating downstream
 40→// tokens.
 41→// ───────────────────────────────────────────────────────────────────────
 42→export const SEND_FILE_RE = /<<SEND_FILE:\s*([^>\r\n]+?)\s*>>/g;
 43→export const SCHEDULE_RE = /<<SCHEDULE:\s*([^>\r\n]+?)\s*>>/g;
 44→export const ASK_RE = /<<ASK:\s*([^>\r\n]+?)\s*>>/g;
 45→// 2026-05-02: reason bodies additionally reject `<` so an agent quoting
 46→// other tokens inside a reason (e.g. <<GOAL_DONE:describes <<RESTART:foo>>>>)
 47→// can't collapse the outer match onto the inner `>>`. SEND_FILE / SCHEDULE
 48→// / ASK bodies keep `<` allowed because their payloads (paths / time specs
 49→// / key=val) don't typically contain it, and banning `<` there would break
 50→// legitimate payloads like URLs.
 51→export const SKILL_USED_RE =
 52→  /<<SKILL_USED:\s*([a-zA-Z0-9_-]{1,60})\s*\|\s*([^<>|\r\n]{0,500})\s*>>/g;
 53→export const GOAL_DONE_RE = /<<GOAL_DONE:\s*([^<>|\r\n]{1,500}?)\s*>>/g;
 54→// RESTART token (C3, 2026-05-02). `<<RESTART:reason>>` or bare
 55→// `<<RESTART>>` asks the bridge to exit(1) so the supervisor respawns us.
 56→// The actual guardrail (goal active? cooldown? cap?) lives in runPrompt;
 57→// this regex only extracts the payload. Reason is 1-500 chars, rejects
 58→// `<` / `>` / `|` / CRLF so malformed payloads (including agents quoting
 59→// other tokens inside the reason) fall through as visible text instead
 60→// of collapsing the match on a nested `>>`.
 61→export const RESTART_RE = /<<RESTART:\s*([^<>|\r\n]{1,500}?)\s*>>/g;
 62→export const RESTART_BARE_RE = /<<RESTART>>/g;
 63→export const RESTART_BARE_REASON = "agent-requested-restart";
 64→export const STICKER_RE = /<<STICKER:\s*([a-z_]{1,20})\s*>>/g;
 65→export const CONTINUE_RE = /<<CONTINUE>>/g;
 66→
 67→// ASK sub-regexes (kept here because ASK payload parsing lives here too).
 68→const ASK_ID_RE = /^[a-zA-Z0-9_-]{1,32}$/;
 69→const ASK_KEY_RE = /^[a-zA-Z0-9_-]{1,20}$/;
 70→const ASK_LABEL_MAX = 40;
 71→// Soft cap: labels over this width are accepted but logged. The skill
 72→// (ms-telegram-ask-button-protocol) mandates >20 -> numbered body list
 73→// with short labels. We do not reject here because rejecting would
 74→// leave the whole token verbatim in chat; a log line gives operators
 75→// something to grep when a user reports crowded/unreadable buttons.
 76→const ASK_LABEL_SOFT = 20;
 77→
 78→// Token-class limits (match docs/ab-token-protocol.md).
 79→export const SCHEDULE_PROMPT_MAX = 1000;
 80→export const SCHEDULE_MAX_PER_MSG = 3;
 81→export const SKILL_USED_MAX_PER_MSG = 5;
 82→export const GOAL_DONE_MAX_PER_MSG = 1;
 83→// RESTART: only honour the first <<RESTART:...>> in one reply. Extra
 84→// tokens stay in visible text as a signal to the agent (same idea as
 85→// GOAL_DONE extra-token handling).
 86→export const RESTART_MAX_PER_MSG = 1;
 87→// 2026-05-03: balanced-body reason cap raised from 200 → 500 and
 88→// switched from hard-reject to silent truncate. Live-observed agent
 89→// failure mode: when a goal takes 10+ turns to complete, the GOAL_DONE
 90→// reason summarising "why I think we're done" routinely runs 300-600
 91→// chinese chars. The old 200-char hard reject left the token verbatim
 92→// in text, goalDone=null, and the bridge kept scheduling continuation
 93→// turns forever ("GOAL_DONE failed to fire" bug fact, 2026-05-03).
 94→// Truncate keeps the token functional while preserving a sane upper
 95→// bound that fits comfortably in the "✓ Goal achieved: <reason>" line
 96→// on Telegram. Same cap applied to SKILL_USED and RESTART for policy
 97→// consistency.
 98→export const BALANCED_REASON_MAX = 500;
