130→// ─── Bot factory with rate-limit observer ─────────────────────────────────────
131→
132→export type RecoveryListener = () => void | Promise<void>;
133→
134→export interface BotSetupResult {
135→  bot: Bot;
136→  rateLimitedUntil: () => number;
137→  onRateLimitRecovery: (fn: RecoveryListener) => () => void;
138→  queuePendingMessage: (chatId: number, text: string) => void;
139→}
140→
141→export function createBot(): BotSetupResult {
142→  const bot = new Bot(config.telegramToken);
143→
144→  bot.api.config.use(
145→    autoRetry({
146→      maxRetryAttempts: 3,
147→      maxDelaySeconds: config.telegramAutoRetryMaxDelaySeconds,
148→    })
149→  );
150→
151→  let rateLimitedUntil = 0;
152→  let lastRateLimitSecs = 0;
153→  let rateLimitChatId: number | undefined;
154→  let rateLimitRecoveryTimer: NodeJS.Timeout | null = null;
155→  const pendingMessages: Array<{ chatId: number; text: string }> = [];
156→  const rateLimitRecoveryListeners: Set<RecoveryListener> = new Set();
157→
158→  async function flushPendingMessages() {
159→    const startCount = pendingMessages.length;
160→    let flushed = 0;
161→    while (pendingMessages.length > 0) {
162→      if (rateLimitedUntil > Date.now()) {
163→        console.warn(
164→          `[rate-limit] flush paused mid-way: flushed ${flushed}/${startCount}, ${pendingMessages.length} remain`,
165→        );
166→        return;
167→      }
168→      const { chatId, text } = pendingMessages.shift()!;
169→      try {
170→        await bot.api.sendMessage(chatId, text);
171→        flushed++;
172→        console.log(`[rate-limit] flushed queued message → chat ${chatId} (${flushed}/${startCount})`);
173→      } catch (err) {
174→        console.error("[rate-limit] replay failed, requeueing:", err);
175→        pendingMessages.unshift({ chatId, text });
176→        return;
177→      }
178→      await new Promise<void>((r) => setTimeout(r, 1100));
179→    }
180→    if (startCount > 0) {
181→      console.log(`[rate-limit] flush complete: ${flushed}/${startCount} delivered`);
182→    }
183→  }
184→
185→  bot.api.config.use(async (prev, method, payload, signal) => {
186→    const res = await prev(method, payload, signal);
187→    const retryAfter = (res as any)?.parameters?.retry_after;
188→    if (typeof retryAfter === "number" && retryAfter > 0) {
189→      const until = Date.now() + retryAfter * 1000;
190→      const chatId = Number((payload as any)?.chat_id);
191→      if (Number.isFinite(chatId)) rateLimitChatId = chatId;
192→      if (until > rateLimitedUntil) {
193→        rateLimitedUntil = until;
194→        if (retryAfter > lastRateLimitSecs) lastRateLimitSecs = retryAfter;
195→        console.warn(
196→          `[rate-limit] Telegram 429: retry_after=${retryAfter}s chat=${
197→            Number.isFinite(chatId) ? chatId : "?"
198→          } method=${method} — pausing edits until ${new Date(until).toISOString()}`
199→        );
200→        if (rateLimitRecoveryTimer) {
201→          clearTimeout(rateLimitRecoveryTimer);
202→          rateLimitRecoveryTimer = null;
203→        }
204→        const waitMs = until - Date.now() + 500;
205→        rateLimitRecoveryTimer = setTimeout(async () => {
206→          rateLimitRecoveryTimer = null;
207→          const peak = lastRateLimitSecs;
208→          const target = rateLimitChatId;
209→          lastRateLimitSecs = 0;
210→          rateLimitedUntil = 0;
211→          console.log(
212→            `[rate-limit] recovered after ${peak}s — flushing ${pendingMessages.length} pending message(s)`
213→          );
214→          if (target === undefined) return;
215→          try {
216→            await bot.api.sendMessage(
217→              target,
218→              `⏳ Telegram 限流解除（等了 ${peak}s）— 現在可以正常收發訊息了。`
219→            );
220→          } catch (err) {
221→            console.error("[rate-limit] failed to send recovery notice:", err);
222→          }
223→          for (const fn of Array.from(rateLimitRecoveryListeners)) {
224→            try {
225→              await fn();
226→            } catch (err) {
227→              console.error("[rate-limit] recovery listener failed:", err);
228→            }
229→          }
230→          await flushPendingMessages();
231→        }, waitMs);
232→      }
233→    }
234→    return res;
235→  });
236→
237→  return {
238→    bot,
239→    rateLimitedUntil: () => rateLimitedUntil,
240→    onRateLimitRecovery(fn: RecoveryListener) {
241→      rateLimitRecoveryListeners.add(fn);
242→      return () => rateLimitRecoveryListeners.delete(fn);
243→    },
244→    queuePendingMessage(chatId: number, text: string) {
245→      pendingMessages.push({ chatId, text });
246→    },
247→  };
248→}
